args.cypher:
// Traverse the HierarchicalStructures submodel to find contained entities
MATCH (sm:Submodel {id: 'urn:submodel:hall4:hierarchicalstructures'})-[:HAS_ELEMENT*]->(e:Entity)-[:REPRESENTS_ASSET]->(asset:Asset)
RETURN e.idShort, e.entityType, asset.globalAssetId

// Find the HierarchicalStructures submodel in Hall4
MATCH (hall:AssetAdministrationShell {idShort: 'Hall4'})-[:HAS_SUBMODEL]->(sm:Submodel {idShort: 'HierarchicalStructures'})
RETURN sm.id AS smId
